import{c as a,Q as r,j as t,m as i}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"From Vibe Coding to Spec-Driven Development","description":"","frontmatter":{"url":"https://towardsdatascience.com/from-vibe-coding-to-spec-driven-development","title":"From Vibe Coding to Spec-Driven Development","author":"Mariya Mansurova","date":"2026-05-12T00:00:00.000Z","status":"success"},"headers":[],"relativePath":"research/ai-articles/22-tds-vibe-to-spec-driven.md","filePath":"research/ai-articles/22-tds-vibe-to-spec-driven.md","lastUpdated":1779894392000}'),o={name:"research/ai-articles/22-tds-vibe-to-spec-driven.md"};function n(l,e,s,d,p,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="from-vibe-coding-to-spec-driven-development" tabindex="-1">From Vibe Coding to Spec-Driven Development <a class="header-anchor" href="#from-vibe-coding-to-spec-driven-development" aria-label="Permalink to &quot;From Vibe Coding to Spec-Driven Development&quot;">​</a></h1><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>Mariya Mansurova 的文章對比 AI 編碼代理啟用的兩種軟體開發方法。Vibe 編碼涉及最小化預先規劃的迭代、對話式精煉——向 LLM 請求功能生成、在本機測試，並請求調整直到結果滿足期望。雖然適合簡單專案，但此方法在可擴展性、團隊協調和機構知識保留上面臨困難。</p><p>規格驅動開發（SDD）透過解耦規格與實作，採用傳統工程嚴謹性。開發人員在編碼開始前投入時間於架構決策和記載的需求。此基礎工作——儲存於存儲庫 markdown 檔案並在整個專案中更新——建立持久的真實來源，在上下文窗口限制和代理轉換中倖存。</p><p>作者強調，即使推廣「vibe 編碼」的 Andrej Karpathy（2025 年 2 月）在一年內也承認其局限性。Karpathy 現在提倡「代理工程」，該方法根據詳細規格協調代理，並由人類監督，而非讓代理從隨意提示進行。</p><h2 id="規格驅動開發工作流結構" tabindex="-1">規格驅動開發工作流結構 <a class="header-anchor" href="#規格驅動開發工作流結構" aria-label="Permalink to &quot;規格驅動開發工作流結構&quot;">​</a></h2><p>方法論包含三個階段：</p><p><strong>憲法建立</strong>透過三份文件確立專案基礎：闡述目的和目標的使命陳述、詳述架構選擇的技術堆棧文件，以及列出實作階段的路線圖。此憲法作為所有後續開發的指導。</p><p><strong>功能開發</strong>遵循可重複的週期：指定詳細需求和成功標準、實作變更、驗證規格、迭代。人類角色從直接寫程式碼轉向引導、審查和進行架構決策。</p><p><strong>重新規劃</strong>涉及在功能完成後暫停以重新評估方向、根據學習重新排定優先順序，並精煉流程。此反思防止累積漂移並維持與原始產品願景的一致性。</p><h2 id="與-vibe-編碼的關鍵區別" tabindex="-1">與 Vibe 編碼的關鍵區別 <a class="header-anchor" href="#與-vibe-編碼的關鍵區別" aria-label="Permalink to &quot;與 Vibe 編碼的關鍵區別&quot;">​</a></h2><p>文章識別 SDD 解決的特定 vibe 編碼局限：</p><ul><li><strong>上下文衰減</strong>：AI 代理無狀態；啟動新對話會喪失先前推理</li><li><strong>缺乏慣例</strong>：無結構，團隊為相同問題開發不一致方法</li><li><strong>失落推理</strong>：聊天歷史清除時決策消失</li><li><strong>可擴展性差</strong>：方法在多個開發人員或複雜程式碼庫上分解</li></ul><p>SDD 跨會話保留上下文、維持架構一致性，並透過持久文件建立可審計決策歷史。</p><h2 id="實際應用" tabindex="-1">實際應用 <a class="header-anchor" href="#實際應用" aria-label="Permalink to &quot;實際應用&quot;">​</a></h2><p>作者展示透過建立 Trainlytics（一個健身追蹤網路應用）的 SDD。整個 MVP——具備使用者認證、活動記錄、鍛鍊歷史和資料持久性——使用 Claude Code 配合 Claude 代理耗時約 4.5 小時端到端。</p><p>開發序列包括：透過代理協助建立憲法（透過多輪審查迭代驗證）、實作第一功能階段（MVP 核心活動記錄）、驗證規格實作，然後根據實際使用經驗重新規劃以重新排定優先順序。</p><h2 id="實作工具" tabindex="-1">實作工具 <a class="header-anchor" href="#實作工具" aria-label="Permalink to &quot;實作工具&quot;">​</a></h2><p>文章提及兩個實踐框架：</p><p><strong>規格工具套件</strong>由 GitHub 提供，透過初始化 <code>.specify/</code> 資料夾和 Claude 命令的自動工作流實作。它簡化 SDD 流程，但更狹隘地聚焦於代碼品質、測試標準和用戶體驗一致性的憲法開發。</p><p>JetBrains DeepLearning.AI 課程方法在憲法本身內維持更寬廣上下文。</p><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><ul><li>Andrej Karpathy 立場演變：從「vibe 編碼」（2025 年 2 月）到「代理工程」（2026 年）</li><li>Trainlytics MVP 開發時間：約 4.5 小時（使用 Claude Code）</li><li>建議對話上限（來自相關研究）：15-20 訊息前啟動新會話</li><li>憲法文件：3 份核心文件（使命、技術堆棧、路線圖）</li></ul><h2 id="核心建議" tabindex="-1">核心建議 <a class="header-anchor" href="#核心建議" aria-label="Permalink to &quot;核心建議&quot;">​</a></h2><p>作者提倡採用 SDD 作為較大專案的預設方法，特別是涉及多個開發人員的專案，同時承認快速特設改進或一次性分析可能不證成預先規格工作。此方法反映基礎工程實踐轉變：人類越來越多地架構系統和協調 AI 代理，而非直接寫程式碼。</p><p>文章結論指出自然語言正成為主要程式設計介面，類似 CodeSpeak 的專案探索此方向，表示更廣泛產業轉向規格驅動、代理協調開發實踐。</p>',26)])])}const u=a(o,[["render",n]]);export{b as __pageData,u as default};
